338→    /*
339→     * show the passed imageUrl in the fullscreen photo activity - optional content is the
340→     * content of the post the image is in, used by the activity to show all images in
341→     * the post
342→     */
343→    public enum PhotoViewerOption {
344→        IS_PRIVATE_IMAGE,
345→        IS_GALLERY_IMAGE
346→    }
347→
348→    public static void showReaderPhotoViewer(Context context,
349→                                             String imageUrl,
350→                                             String content,
351→                                             View sourceView,
352→                                             EnumSet<PhotoViewerOption> imageOptions,
353→                                             int startX,
354→                                             int startY) {
355→        if (context == null || TextUtils.isEmpty(imageUrl)) {
356→            return;
357→        }
358→
359→        boolean isPrivate = imageOptions != null && imageOptions.contains(PhotoViewerOption.IS_PRIVATE_IMAGE);
360→        boolean isGallery = imageOptions != null && imageOptions.contains(PhotoViewerOption.IS_GALLERY_IMAGE);
361→
362→        Intent intent = new Intent(context, ReaderPhotoViewerActivity.class);
363→        intent.putExtra(ReaderConstants.ARG_IMAGE_URL, imageUrl);
364→        intent.putExtra(ReaderConstants.ARG_IS_PRIVATE, isPrivate);
365→        intent.putExtra(ReaderConstants.ARG_IS_GALLERY, isGallery);
366→        if (!TextUtils.isEmpty(content)) {
367→            intent.putExtra(ReaderConstants.ARG_CONTENT, content);
368→        }
369→
370→        if (context instanceof Activity && sourceView != null) {
371→            Activity activity = (Activity) context;
372→            ActivityOptionsCompat options =
373→                    ActivityOptionsCompat.makeScaleUpAnimation(sourceView, startX, startY, 0, 0);
374→            ActivityCompat.startActivity(activity, intent, options.toBundle());
375→        } else {
376→            context.startActivity(intent);
377→        }
378→    }
379→
