307→    @Override
308→    protected void onActivityResult(int requestCode, int resultCode, Intent data) {
309→        super.onActivityResult(requestCode, resultCode, data);
310→
311→        switch (requestCode) {
312→            case RequestCodes.NO_REBLOG_SITE:
313→                if (resultCode == Activity.RESULT_OK) {
314→                    finish(); // Finish activity to make My Site page visible
315→                }
316→                break;
317→            case RequestCodes.EDIT_POST:
318→                if (resultCode == Activity.RESULT_OK && data != null && !isFinishing()) {
319→                    int localId = data.getIntExtra(EditPostActivity.EXTRA_POST_LOCAL_ID, 0);
320→                    final SiteModel site = (SiteModel) data.getSerializableExtra(WordPress.SITE);
321→                    final PostModel post = mPostStore.getPostByLocalPostId(localId);
322→
323→                    if (EditPostActivity.checkToRestart(data)) {
324→                        ActivityLauncher.editPostOrPageForResult(data, ReaderPostListActivity.this, site,
325→                                data.getIntExtra(EditPostActivity.EXTRA_POST_LOCAL_ID, 0));
326→                        // a restart will happen so, no need to continue here
327→                        return;
328→                    }
329→
330→                    if (site != null && post != null) {
331→                        mUploadUtilsWrapper.handleEditPostResultSnackbars(
332→                                this,
333→                                findViewById(R.id.coordinator),
334→                                data,
335→                                post,
336→                                site,
337→                                mUploadActionUseCase.getUploadAction(post),
338→                                new View.OnClickListener() {
339→                                    @Override
340→                                    public void onClick(View v) {
341→                                        UploadUtils.publishPost(
342→                                                ReaderPostListActivity.this,
343→                                                post,
344→                                                site,
345→                                                mDispatcher
346→                                        );
347→                                    }
348→                                });
349→                    }
350→                }
351→                break;
352→        }
353→    }
