253→
254→        void restoreInstance(Bundle bundle) {
255→            clear();
256→            if (bundle.containsKey(mKeyName)) {
257→                ArrayList<String> history = bundle.getStringArrayList(mKeyName);
258→                if (history != null) {
259→                    this.addAll(history);
260→                }
261→            }
262→        }
263→
264→        void saveInstance(Bundle bundle) {
265→            if (!isEmpty()) {
266→                ArrayList<String> history = new ArrayList<>();
267→                history.addAll(this);
268→                bundle.putStringArrayList(mKeyName, history);
269→            }
270→        }
271→    }
