801→    private void resumeFollowedTag() {
802→        TagAdded addedTag = EventBus.getDefault().getStickyEvent(ReaderEvents.TagAdded.class);
803→        if (isFollowingScreen() && addedTag != null) {
804→            EventBus.getDefault().removeStickyEvent(addedTag);
805→            // user just added a tag so switch to it.
806→            ReaderTag newTag = ReaderUtils.getTagFromTagName(addedTag.getTagName(), ReaderTagType.FOLLOWED);
807→            mSubFilterViewModel.setSubfilterFromTag(newTag);
808→        } else if (isFollowingScreen() && !ReaderTagTable.tagExists(getCurrentTag())) {
809→            // user just removed a tag which was selected in the subfilter
810→            mSubFilterViewModel.setDefaultSubfilter();
811→        } else {
812→            // otherwise, refresh posts to make sure any changes are reflected and auto-update
813→            // posts in the current tag if it's time
814→            refreshPosts();
815→            updateCurrentTagIfTime();
816→        }
817→    }
