 89→    private static void requestPostsWithTag(final ReaderTag tag,
 90→                                            final UpdateAction updateAction,
 91→                                            final ReaderActions.UpdateResultListener resultListener) {
 92→        String path = getRelativeEndpointForTag(tag);
 93→        if (TextUtils.isEmpty(path)) {
 94→            resultListener.onUpdateResult(ReaderActions.UpdateResult.FAILED);
 95→            return;
 96→        }
 97→
 98→        StringBuilder sb = new StringBuilder(path);
 99→
100→        // append #posts to retrieve
101→        sb.append("?number=").append(ReaderConstants.READER_MAX_POSTS_TO_REQUEST);
102→
103→        // return newest posts first (this is the default, but make it explicit since it's important)
104→        sb.append("&order=DESC");
105→
106→        String beforeDate;
107→        switch (updateAction) {
108→            case REQUEST_OLDER:
109→                // request posts older than the oldest existing post with this tag
110→                beforeDate = ReaderPostTable.getOldestDateWithTag(tag);
111→                break;
112→            case REQUEST_OLDER_THAN_GAP:
113→                // request posts older than the post with the gap marker for this tag
114→                beforeDate = ReaderPostTable.getGapMarkerDateForTag(tag);
115→                break;
116→            case REQUEST_NEWER:
117→            case REQUEST_REFRESH:
118→            default:
119→                beforeDate = null;
120→                break;
121→        }
122→        if (!TextUtils.isEmpty(beforeDate)) {
123→            sb.append("&before=").append(UrlUtils.urlEncode(beforeDate));
124→        }
125→
126→        sb.append("&meta=site,likes");
127→
128→        com.wordpress.rest.RestRequest.Listener listener = new RestRequest.Listener() {
129→            @Override
130→            public void onResponse(JSONObject jsonObject) {
131→                // remember when this tag was updated if newer posts were requested
132→                if (updateAction == UpdateAction.REQUEST_NEWER || updateAction == UpdateAction.REQUEST_REFRESH) {
133→                    ReaderTagTable.setTagLastUpdated(tag);
134→                }
135→                handleUpdatePostsResponse(tag, jsonObject, updateAction, resultListener);
136→            }
137→        };
138→        RestRequest.ErrorListener errorListener = new RestRequest.ErrorListener() {
139→            @Override
140→            public void onErrorResponse(VolleyError volleyError) {
141→                AppLog.e(AppLog.T.READER, volleyError);
142→                resultListener.onUpdateResult(ReaderActions.UpdateResult.FAILED);
143→            }
144→        };
145→
146→        WordPress.getRestClientUtilsV1_2().get(sb.toString(), null, null, listener, errorListener);
147→    }
