325→    /*
326→     * returns the passed endpoint without the unnecessary path - this is
327→     * needed because as of 20-Feb-2015 the /read/menu/ call returns the
328→     * full path but we don't want to use the full path since it may change
329→     * between API versions (as it did when we moved from v1 to v1.1)
330→     *
331→     * ex: https://public-api.wordpress.com/rest/v1/read/tags/fitness/posts
332→     * becomes just read/tags/fitness/posts
333→     */
334→    private static String getRelativeEndpoint(final String endpoint) {
335→        if (endpoint != null && endpoint.startsWith("http")) {
336→            int pos = endpoint.indexOf("/read/");
337→            if (pos > -1) {
338→                return endpoint.substring(pos + 1, endpoint.length());
339→            }
340→            pos = endpoint.indexOf("/v1/");
341→            if (pos > -1) {
342→                return endpoint.substring(pos + 4, endpoint.length());
343→            }
344→        }
345→        return StringUtils.notNullStr(endpoint);
346→    }
347→}
