225→    /*
226→     * purge table of unattached/older posts - no need to wrap this in a transaction since it's
227→     * only called from ReaderDatabase.purge() which already creates a transaction
228→     */
229→    protected static int purge(SQLiteDatabase db) {
230→        // delete posts attached to tags that no longer exist
231→        int numDeleted = db.delete("tbl_posts", "tag_name NOT IN (SELECT DISTINCT tag_name FROM tbl_tags)", null);
232→
233→        // delete excess posts on a per-tag basis
234→        ReaderTagList tags = ReaderTagTable.getAllTags();
235→        for (ReaderTag tag : tags) {
236→            numDeleted += purgePostsForTag(db, tag);
237→        }
238→
239→        numDeleted += purgeUnbookmarkedPostsWithBookmarkTag();
240→
241→        // delete search results
242→        numDeleted += purgeSearchResults(db);
243→        return numDeleted;
244→    }
