855→    /**
856→     * Android's CursorWindow has a max size of 2MB per row which can be exceeded
857→     * with a very large text column, causing an IllegalStateException when the
858→     * row is read - prevent this by limiting the amount of text that's stored in
859→     * the text column - note that this situation very rarely occurs
860→     * http://bit.ly/2Fs7B78
861→     * http://bit.ly/2oOKCJc
862→     */
863→    private static final int MAX_TEXT_LEN = (1024 * 1024) / 2;
864→
865→    private static String maxText(final ReaderPost post) {
866→        if (post.getText().length() <= MAX_TEXT_LEN) {
867→            return post.getText();
868→        }
869→        // if the post has an excerpt (which should always be the case), store it as the full text
870→        // with a link to the full article
871→        if (post.hasExcerpt()) {
872→            AppLog.w(AppLog.T.READER, "reader post table > max text exceeded, storing excerpt");
873→            return "<p>" + post.getExcerpt() + "</p>"
874→                   + String.format("<p style='text-align:center'><a href='%s'>%s</a></p>",
875→                    post.getUrl(),
876→                    WordPress.getContext().getString(R.string.reader_label_view_original));
877→        } else {
878→            AppLog.w(AppLog.T.READER, "reader post table > max text exceeded, storing truncated text");
879→            return post.getText().substring(0, MAX_TEXT_LEN);
880→        }
881→    }
