982→        String columns = (excludeTextColumn ? COLUMN_NAMES_NO_TEXT : "*");
983→        String sql = "SELECT " + columns + " FROM tbl_posts WHERE tag_name=? AND tag_type=?";
984→
985→        if (tag.tagType == ReaderTagType.DEFAULT) {
986→            // skip posts that are no longer liked if this is "Posts I Like", skip posts that are no
987→            // longer followed if this is "Followed Sites"
