 49→    /*
 50→     * replaces all tags with the passed list
 51→     */
 52→    public static void replaceTags(ReaderTagList tags) {
 53→        if (tags == null || tags.size() == 0) {
 54→            return;
 55→        }
 56→
 57→        SQLiteDatabase db = ReaderDatabase.getWritableDb();
 58→        db.beginTransaction();
 59→        try {
 60→            try {
 61→                // first delete all existing tags, then insert the passed ones
 62→                db.execSQL("DELETE FROM tbl_tags");
 63→                addOrUpdateTags(tags);
 64→                db.setTransactionSuccessful();
 65→            } catch (SQLException e) {
 66→                AppLog.e(T.READER, e);
 67→            }
 68→        } finally {
 69→            db.endTransaction();
 70→        }
 71→    }
