 78→            return;
 79→        }
 80→
 81→        SQLiteDatabase db = ReaderDatabase.getWritableDb();
 82→        db.beginTransaction();
 83→        try {
 84→            try {
 85→                // first delete all existing followed tags, then insert the passed ones
 86→                String[] args = {Integer.toString(ReaderTagType.FOLLOWED.toInt())};
 87→                db.execSQL("DELETE FROM tbl_tags WHERE tag_type=?", args);
 88→                addOrUpdateTags(tags);
 89→                db.setTransactionSuccessful();
 90→            } catch (SQLException e) {
 91→                AppLog.e(T.READER, e);
 92→            }
 93→        } finally {
