119→                stmt.bindString(2, tag.getTagDisplayName());
120→                stmt.bindString(3, tag.getTagTitle());
121→                stmt.bindLong(4, tag.tagType.toInt());
122→                stmt.bindString(5, tag.getEndpoint());
