 86→    public static ReaderPost fromJson(JSONObject json) {
 87→        if (json == null) {
 88→            throw new IllegalArgumentException("null json post");
 89→        }
 90→
 91→        ReaderPost post = new ReaderPost();
 92→
 93→        post.postId = json.optLong(ReaderConstants.POST_ID);
 94→        post.blogId = json.optLong(ReaderConstants.POST_SITE_ID);
 95→        post.feedId = json.optLong("feed_ID");
 96→        post.feedItemId = json.optLong("feed_item_ID");
 97→
 98→        if (json.has(ReaderConstants.POST_PSEUDO_ID)) {
 99→            post.mPseudoId = JSONUtils.getString(json, ReaderConstants.POST_PSEUDO_ID); // read/ endpoint
100→        } else {
101→            post.mPseudoId = JSONUtils.getString(json, "global_ID"); // sites/ endpoint
102→        }
103→
104→        // remove HTML from the excerpt
105→        post.mExcerpt = HtmlUtils.fastStripHtml(JSONUtils.getString(json, "excerpt")).trim();
106→
107→        post.mText = JSONUtils.getString(json, "content");
108→        post.mTitle = JSONUtils.getStringDecoded(json, "title");
109→        post.mFormat = JSONUtils.getString(json, "format");
110→        post.mUrl = JSONUtils.getString(json, "URL");
111→        post.mShortUrl = JSONUtils.getString(json, "short_URL");
112→        post.setBlogUrl(JSONUtils.getString(json, "site_URL"));
113→
114→        post.numLikes = json.optInt("like_count");
115→        post.isLikedByCurrentUser = JSONUtils.getBool(json, "i_like");
116→        post.isFollowedByCurrentUser = JSONUtils.getBool(json, "is_following");
117→        post.isExternal = JSONUtils.getBool(json, "is_external");
118→        post.isPrivate = JSONUtils.getBool(json, "site_is_private");
119→        post.isPrivateAtomic = JSONUtils.getBool(json, "site_is_atomic");
120→        post.isJetpack = JSONUtils.getBool(json, "is_jetpack");
121→        post.useExcerpt = JSONUtils.getBool(json, "use_excerpt");
122→        post.isSeen = JSONUtils.getBool(json, "is_seen");
123→        post.isSeenSupported = json.has("is_seen");
124→
125→        JSONObject jsonDiscussion = json.optJSONObject("discussion");
126→        if (jsonDiscussion != null) {
127→            post.isCommentsOpen = JSONUtils.getBool(jsonDiscussion, "comments_open");
128→            post.numReplies = jsonDiscussion.optInt("comment_count");
129→        } else {
130→            post.isCommentsOpen = JSONUtils.getBool(json, "comments_open");
131→            post.numReplies = json.optInt("comment_count");
132→        }
133→
134→        // parse the author section
135→        assignAuthorFromJson(post, json.optJSONObject("author"));
136→
137→        post.mFeaturedImage = JSONUtils.getString(json, "featured_image");
138→        post.mBlogName = JSONUtils.getStringDecoded(json, "site_name");
139→
140→        post.mDatePublished = JSONUtils.getString(json, "date");
141→        post.mDateLiked = JSONUtils.getString(json, "date_liked");
142→        post.mDateTagged = JSONUtils.getString(json, "tagged_on");
143→
144→        // "score" only exists for search results
145→        post.score = json.optDouble("score");
146→
147→        // remove html from title (rare, but does happen)
148→        if (post.hasTitle() && post.mTitle.contains("<") && post.mTitle.contains(">")) {
149→            post.mTitle = HtmlUtils.stripHtml(post.mTitle);
150→        }
151→
152→        // parse the tags section
153→        assignTagsFromJson(post, json.optJSONObject("tags"));
154→
155→        // parse the attachments
156→        JSONObject jsonAttachments = json.optJSONObject("attachments");
157→        if (jsonAttachments != null && jsonAttachments.length() > 0) {
158→            post.mAttachmentsJson = jsonAttachments.toString();
159→        }
160→
161→        // site metadata - returned when ?meta=site was added to the request
162→        JSONObject jsonSite = JSONUtils.getJSONChild(json, "meta/data/site");
163→        if (jsonSite != null) {
164→            post.blogId = jsonSite.optInt("ID");
165→            post.mBlogName = JSONUtils.getString(jsonSite, "name");
166→            post.setBlogUrl(JSONUtils.getString(jsonSite, "URL"));
167→            post.isPrivate = JSONUtils.getBool(jsonSite, "is_private");
168→            JSONObject jsonSiteIcon = jsonSite.optJSONObject("icon");
169→            if (jsonSiteIcon != null) {
170→                post.mBlogImageUrl = JSONUtils.getString(jsonSiteIcon, "img");
171→            }
172→            // TODO: as of 29-Sept-2014, this is broken - endpoint returns false when it should be true
173→            post.isJetpack = JSONUtils.getBool(jsonSite, "jetpack");
174→
175→            post.organizationId = jsonSite.optInt("organization_id");
176→        }
177→
178→        // "discover" posts
179→        JSONObject jsonDiscover = json.optJSONObject("discover_metadata");
180→        if (jsonDiscover != null) {
181→            post.setDiscoverJson(jsonDiscover.toString());
182→        }
183→
184→        // xpost info
185→        assignXpostIdsFromJson(post, json.optJSONArray("metadata"));
186→
187→        // if there's no featured image, check if featured media has been set to an image
188→        if (!post.hasFeaturedImage() && json.has("featured_media")) {
189→            JSONObject jsonMedia = json.optJSONObject("featured_media");
190→            String type = JSONUtils.getString(jsonMedia, "type");
191→            if (type.equals("image")) {
192→                post.mFeaturedImage = JSONUtils.getString(jsonMedia, "uri");
193→            }
194→        }
195→
196→        // if the post doesn't have a featured image but it contains an IMG tag, check whether
197→        // we can find a suitable image from the content
198→        if (!post.hasFeaturedImage() && post.hasImages()) {
199→            post.mFeaturedImage = new ReaderImageScanner(post.mText, post.isPrivate)
200→                    .getLargestImage(ReaderConstants.MIN_FEATURED_IMAGE_WIDTH);
201→        }
202→
203→        // if there's no featured image or featured video and the post contains an iframe, scan
204→        // the content for a suitable featured video
205→        if (!post.hasFeaturedImage()
206→            && !post.hasFeaturedVideo()
207→            && post.getText().contains("<iframe")) {
208→            post.setFeaturedVideo(new ReaderIframeScanner(post.getText()).getFirstUsableVideo());
209→        }
210→
211→        // "railcar" data - currently used in search streams, used by TrainTracks
212→        JSONObject jsonRailcar = json.optJSONObject("railcar");
213→        if (jsonRailcar != null) {
214→            post.setRailcarJson(jsonRailcar.toString());
215→        }
216→
217→        // set the card type last since it depends on information contained in the post - note
218→        // that this is stored in the post table rather than calculated on-the-fly
219→        post.setCardType(ReaderCardType.fromReaderPost(post));
220→
221→        return post;
222→    }
