228→    /*
229→     * assigns cross post blog & post IDs from post's metadata section
230→     * "metadata": [
231→     * {
232→     * "id": "21192",
233→     * "key": "xpost_origin",
234→     * "value": "11326809:18427"
235→     * }
236→     * ],
237→     */
238→    private static void assignXpostIdsFromJson(ReaderPost post, JSONArray jsonMetadata) {
239→        if (jsonMetadata == null) {
240→            return;
241→        }
242→
243→        for (int i = 0; i < jsonMetadata.length(); i++) {
244→            JSONObject jsonMetaItem = jsonMetadata.optJSONObject(i);
245→            if (jsonMetaItem != null) {
246→                String metaKey = jsonMetaItem.optString("key");
247→                if (!TextUtils.isEmpty(metaKey) && metaKey.equals("xpost_origin")) {
248→                    String value = jsonMetaItem.optString("value");
249→                    if (!TextUtils.isEmpty(value) && value.contains(":")) {
250→                        String[] valuePair = value.split(":");
251→                        if (valuePair.length == 2) {
252→                            post.xpostBlogId = StringUtils.stringToLong(valuePair[0]);
253→                            post.xpostPostId = StringUtils.stringToLong(valuePair[1]);
254→                            return;
255→                        }
256→                    }
257→                }
258→            }
259→        }
260→    }
