262→    /*
263→     * assigns author-related info to the passed post from the passed JSON "author" object
264→     */
265→    private static void assignAuthorFromJson(ReaderPost post, JSONObject jsonAuthor) {
266→        if (jsonAuthor == null) {
267→            return;
268→        }
269→
270→        post.mAuthorName = JSONUtils.getStringDecoded(jsonAuthor, "name");
271→        post.mAuthorFirstName = JSONUtils.getStringDecoded(jsonAuthor, "first_name");
272→        post.authorId = jsonAuthor.optLong("ID");
273→        post.authorBlogId = jsonAuthor.optLong("site_ID");
274→
275→        // v1.2 endpoint contains a "has_avatar" boolean which tells us whether the author
276→        // has a valid avatar - if this field exists and is set to false, skip setting
277→        // the avatar URL
278→        boolean hasAvatar;
279→        if (jsonAuthor.has("has_avatar")) {
280→            hasAvatar = jsonAuthor.optBoolean("has_avatar");
281→        } else {
282→            hasAvatar = true;
283→        }
284→        if (hasAvatar) {
285→            post.mPostAvatar = JSONUtils.getString(jsonAuthor, "avatar_URL");
286→        }
287→
288→        // site_URL doesn't exist for /sites/ endpoints, so get it from the author
289→        if (TextUtils.isEmpty(post.mBlogUrl)) {
290→            post.setBlogUrl(JSONUtils.getString(jsonAuthor, "URL"));
291→        }
292→
293→        post.setAuthorBlogUrl(JSONUtils.getString(jsonAuthor, "URL"));
294→    }
