296→    /*
297→     * assigns primary/secondary tags to the passed post from the passed JSON "tags" object
298→     */
299→    private static void assignTagsFromJson(ReaderPost post, JSONObject jsonTags) {
300→        if (jsonTags == null) {
301→            return;
302→        }
303→
304→        Iterator<String> it = jsonTags.keys();
305→        if (!it.hasNext()) {
306→            return;
307→        }
308→
309→        // most popular tag & second most popular tag, based on usage count on this blog
310→        String mostPopularTag = null;
311→        String nextMostPopularTag = null;
312→        int popularCount = 0;
313→
314→        ReaderTagList tags = new ReaderTagList();
315→        while (it.hasNext()) {
316→            JSONObject jsonThisTag = jsonTags.optJSONObject(it.next());
317→            String thisTagName = UrlUtils.urlDecode(JSONUtils.getString(jsonThisTag, "slug"));
318→
319→            ReaderTag tag = ReaderUtils.getTagFromTagName(thisTagName, ReaderTagType.DEFAULT);
320→            tags.add(tag);
321→
322→            // if the number of posts on this blog that use this tag is higher than previous,
323→            // set this as the most popular tag, and set the second most popular tag to
324→            // the current most popular tag
325→            int postCount = jsonThisTag.optInt("post_count");
326→            if (postCount > popularCount) {
327→                nextMostPopularTag = mostPopularTag;
328→                mostPopularTag = thisTagName;
329→                popularCount = postCount;
330→            } else if (nextMostPopularTag == null) {
331→                nextMostPopularTag = thisTagName;
332→            }
333→        }
334→
335→        // don't set primary tag if one is already set
336→        if (!post.hasPrimaryTag()) {
337→            post.setPrimaryTag(mostPopularTag);
338→        }
339→        post.setSecondaryTag(nextMostPopularTag);
340→        post.setTags(tags);
341→    }
