 99→            mPostListType = ReaderTypes.DEFAULT_POST_LIST_TYPE;
100→        }
101→
102→        if (getPostListType() == ReaderPostListType.TAG_PREVIEW
103→            || getPostListType() == ReaderPostListType.BLOG_PREVIEW) {
104→            toolbar.setNavigationOnClickListener(view -> finish());
105→
106→            if (getPostListType() == ReaderPostListType.BLOG_PREVIEW) {
107→                setTitle(R.string.reader_title_blog_preview);
108→                if (savedInstanceState == null) {
109→                    long blogId = getIntent().getLongExtra(ReaderConstants.ARG_BLOG_ID, 0);
110→                    long feedId = getIntent().getLongExtra(ReaderConstants.ARG_FEED_ID, 0);
111→                    if (feedId != 0) {
112→                        showListFragmentForFeed(feedId);
113→                        mSiteId = feedId;
114→                    } else {
115→                        showListFragmentForBlog(blogId);
116→                        mSiteId = blogId;
