705→    private void changeReaderMode(ReaderModeInfo readerModeInfo, boolean onlyOnChanges) {
706→        boolean changesDetected = false;
707→
708→        if (onlyOnChanges) {
709→            changesDetected = (readerModeInfo.getTag() != null
710→                               && mCurrentTag != null
711→                               && !readerModeInfo.getTag().equals(mCurrentTag))
712→                              || (mPostListType != readerModeInfo.getListType())
713→                              || (mCurrentBlogId != readerModeInfo.getBlogId())
714→                              || (mCurrentFeedId != readerModeInfo.getFeedId())
715→                              || (readerModeInfo.isFirstLoad());
716→
717→            if (changesDetected && !readerModeInfo.isFirstLoad()) {
718→                trackTagLoaded(readerModeInfo.getTag());
719→            }
720→        }
721→
722→        if (onlyOnChanges && !changesDetected) return;
723→
724→        if (readerModeInfo.getTag() != null) {
725→            mCurrentTag = readerModeInfo.getTag();
726→        }
727→
728→        mPostListType = readerModeInfo.getListType();
729→        mCurrentBlogId = readerModeInfo.getBlogId();
730→        mCurrentFeedId = readerModeInfo.getFeedId();
731→
732→        resetPostAdapter(mPostListType);
733→        if (readerModeInfo.getRequestNewerPosts()) {
734→            updatePosts(false);
735→        }
736→    }
