750→    @Override
751→    public void onResume() {
752→        super.onResume();
753→        /*
754→         * This is a workaround for https://github.com/wordpress-mobile/WordPress-Android/issues/11985.
755→         * The RecyclerView doesn't get redrawn correctly when the adapter finishes its initialization in onStart.
756→         */
757→        getPostAdapter().notifyDataSetChanged();
758→        if (mWasPaused) {
759→            AppLog.d(T.READER, "reader post list > resumed from paused state");
760→            mWasPaused = false;
761→
762→            Site currentSite;
763→
764→            if (getPostListType() == ReaderPostListType.TAG_FOLLOWED) {
765→                resumeFollowedTag();
766→            } else if ((currentSite = getSiteIfBlogPreview()) != null) {
767→                resumeFollowedSite(currentSite);
768→            } else {
769→                refreshPosts();
770→            }
771→
772→            if (mIsTopLevel) {
773→                // Remove sticky event if not consumed
774→                EventBus.getDefault().removeStickyEvent(ReaderEvents.TagAdded.class);
775→            }
776→
777→            // if the user tapped a site to show site preview, it's possible they also changed the follow
778→            // status so tell the search adapter to check whether it has the correct follow status
779→            if (isSearching() && mLastTappedSiteSearchResult != null) {
780→                getSiteSearchAdapter().checkFollowStatusForSite(mLastTappedSiteSearchResult);
781→                mLastTappedSiteSearchResult = null;
782→            }
783→
784→            if (isSearching()) {
785→                return;
786→            }
787→        }
788→
789→        if (shouldShowEmptyViewForSelfHostedCta()) {
790→            setEmptyTitleDescriptionAndButton(false);
791→            showEmptyView();
792→        }
793→
794→        mViewModel.onFragmentResume(mIsTopLevel, isSearching(), isFilterableScreen(),
795→                isFilterableScreen() ? mSubFilterViewModel.getCurrentSubfilterValue() : null);
796→    }
