208→    /*
209→     * called after requesting posts with a specific tag or in a specific blog/feed
210→     */
211→    private static void handleUpdatePostsResponse(final ReaderTag tag,
212→                                                  final JSONObject jsonObject,
213→                                                  final UpdateAction updateAction,
214→                                                  final ReaderActions.UpdateResultListener resultListener) {
215→        if (jsonObject == null) {
216→            resultListener.onUpdateResult(ReaderActions.UpdateResult.FAILED);
217→            return;
218→        }
219→
220→        new Thread() {
221→            @Override
222→            public void run() {
223→                ReaderPostList serverPosts = ReaderPostList.fromJson(jsonObject);
224→                ReaderActions.UpdateResult updateResult = ReaderPostTable.comparePosts(serverPosts);
225→                if (updateResult.isNewOrChanged()) {
226→                    // gap detection - only applies to posts with a specific tag
227→                    ReaderPost postWithGap = null;
228→                    if (tag != null) {
229→                        switch (updateAction) {
230→                            case REQUEST_NEWER:
231→                                // if there's no overlap between server and local (ie: all server
232→                                // posts are new), assume there's a gap between server and local
233→                                // provided that local posts exist
234→                                int numServerPosts = serverPosts.size();
235→                                if (numServerPosts >= 2
236→                                    && ReaderPostTable.getNumPostsWithTag(tag) > 0
237→                                    && !ReaderPostTable.hasOverlap(serverPosts, tag)) {
238→                                    // treat the second to last server post as having a gap
239→                                    postWithGap = serverPosts.get(numServerPosts - 2);
240→                                    // remove the last server post to deal with the edge case of
241→                                    // there actually not being a gap between local & server
242→                                    serverPosts.remove(numServerPosts - 1);
243→                                    ReaderBlogIdPostId gapMarker = ReaderPostTable.getGapMarkerIdsForTag(tag);
244→                                    if (gapMarker != null) {
245→                                        // We mustn't have two gapMarkers at the same time. Therefor we need to
246→                                        // delete all posts before the current gapMarker and clear the gapMarker flag.
247→                                        ReaderPostTable.deletePostsBeforeGapMarkerForTag(tag);
248→                                        ReaderPostTable.removeGapMarkerForTag(tag);
249→                                    }
250→                                }
251→                                break;
252→                            case REQUEST_OLDER_THAN_GAP:
253→                                // if service was started as a request to fill a gap, delete existing posts
254→                                // before the one with the gap marker, then remove the existing gap marker
255→                                ReaderPostTable.deletePostsBeforeGapMarkerForTag(tag);
256→                                ReaderPostTable.removeGapMarkerForTag(tag);
257→                                break;
258→                            case REQUEST_REFRESH:
259→                                ReaderPostTable.deletePostsWithTag(tag);
260→                                break;
261→                            case REQUEST_OLDER:
262→                                // no-op
263→                                break;
264→                        }
265→                    }
266→                    ReaderPostTable.addOrUpdatePosts(tag, serverPosts);
267→                    if (AppPrefs.shouldUpdateBookmarkPostsPseudoIds(tag)) {
268→                        ReaderPostTable.updateBookmarkedPostPseudoId(serverPosts);
269→                        AppPrefs.setBookmarkPostsPseudoIdsUpdated();
270→                    }
271→
272→                    // gap marker must be set after saving server posts
273→                    if (postWithGap != null) {
274→                        ReaderPostTable.setGapMarkerForTag(postWithGap.blogId, postWithGap.postId, tag);
275→                        AppLog.d(AppLog.T.READER, "added gap marker to tag " + tag.getTagNameForLog());
276→                    }
277→                } else if (updateResult == ReaderActions.UpdateResult.UNCHANGED
278→                           && updateAction == UpdateAction.REQUEST_OLDER_THAN_GAP) {
279→                    // edge case - request to fill gap returned nothing new, so remove the gap marker
280→                    ReaderPostTable.removeGapMarkerForTag(tag);
281→                    AppLog.w(AppLog.T.READER, "attempt to fill gap returned nothing new");
282→                }
283→                AppLog.d(AppLog.T.READER, "requested posts response = " + updateResult.toString());
284→                resultListener.onUpdateResult(updateResult);
285→            }
286→        }.start();
287→    }
