289→    /*
290→     * returns the endpoint to use when requesting posts with the passed tag
291→     */
292→    private static String getRelativeEndpointForTag(ReaderTag tag) {
293→        if (tag == null) {
294→            return null;
295→        }
296→
297→        // if passed tag has an assigned endpoint, return it and be done
298→        if (!TextUtils.isEmpty(tag.getEndpoint())) {
299→            return getRelativeEndpoint(tag.getEndpoint());
300→        }
301→
302→        // check the db for the endpoint
303→        String endpoint = ReaderTagTable.getEndpointForTag(tag);
304→        if (!TextUtils.isEmpty(endpoint)) {
305→            return getRelativeEndpoint(endpoint);
306→        }
307→
308→        // never hand craft the endpoint for default tags, since these MUST be updated
309→        // using their stored endpoints
310→        if (tag.tagType == ReaderTagType.DEFAULT) {
311→            return null;
312→        }
313→        return formatRelativeEndpointForTag(tag.getTagSlug());
314→    }
315→
316→    private static String formatRelativeEndpointForTag(@NonNull final String tagSlug) {
317→        return String.format("read/tags/%s/posts", ReaderUtils.sanitizeWithDashes(tagSlug));
318→    }
319→
320→    public static String formatFullEndpointForTag(@NonNull final String tagSlug) {
321→        return WordPress.getRestClientUtilsV1_2().getRestClient().getEndpointURL()
322→               + formatRelativeEndpointForTag(tagSlug);
323→    }
