246→    /**
247→     * When the user unbookmarks a post, we keep the row in the database, but we just change the is_bookmarked flag
248→     * to false, so we can show "undo" items in the saved posts list. This method purges database from such rows.
249→     */
250→    public static int purgeUnbookmarkedPostsWithBookmarkTag() {
251→        int numDeleted = 0;
252→        ReaderTagList tags = ReaderTagTable.getAllTags();
253→        for (ReaderTag tag : tags) {
254→            if (tag.isBookmarked()) {
255→                // delete posts which has a bookmark tag but is_bookmarked flag is false
256→                String[] args = {tag.getTagSlug(), Integer.toString(tag.tagType.toInt())};
257→                numDeleted += ReaderDatabase.getWritableDb()
258→                                            .delete("tbl_posts", "tag_name=? AND tag_type=? AND is_bookmarked=0", args);
259→            }
260→        }
261→        if (numDeleted > 0) {
262→            EventBus.getDefault().post(ReaderPostTableActionEnded.INSTANCE);
263→        }
264→        return numDeleted;
265→    }
