268→     * purge excess posts in the passed tag
269→     */
270→    private static final int MAX_POSTS_PER_TAG = ReaderConstants.READER_MAX_POSTS_TO_DISPLAY;
271→
272→    private static int purgePostsForTag(SQLiteDatabase db, ReaderTag tag) {
273→        int numPosts = getNumPostsWithTag(tag);
274→        if (numPosts <= MAX_POSTS_PER_TAG) {
275→            return 0;
276→        }
277→        String tagName = tag.getTagSlug();
278→        String tagType = Integer.toString(tag.tagType.toInt());
279→        String[] args = {tagName, tagType, tagName, tagType, Integer.toString(MAX_POSTS_PER_TAG)};
280→        String where = "tag_name=? AND tag_type=? AND pseudo_id NOT IN (SELECT DISTINCT pseudo_id FROM tbl_posts WHERE "
281→                       + "tag_name=? AND tag_type=? ORDER BY " + getSortColumnForTag(tag) + " DESC LIMIT ?)";
282→        int numDeleted = db.delete("tbl_posts", where, args);
283→        AppLog.d(AppLog.T.READER,
284→                String.format(Locale.ENGLISH, "reader post table > purged %d posts in tag %s", numDeleted,
285→                        tag.getTagNameForLog()));
286→        return numDeleted;
287→    }
