325→    public static void updatePost(@NonNull ReaderPost post) {
326→        // we need to update a few important fields across all instances of this post - this is
327→        // necessary because a post can exist multiple times in the table with different tags
328→        ContentValues values = new ContentValues();
329→        values.put("title", post.getTitle());
