422→    /*
423→     * returns whether any of the passed posts are new or changed - used after posts are retrieved
424→     */
425→    public static ReaderActions.UpdateResult comparePosts(ReaderPostList posts) {
426→        if (posts == null || posts.size() == 0) {
427→            return ReaderActions.UpdateResult.UNCHANGED;
428→        }
429→
430→        boolean hasChanges = false;
431→        for (ReaderPost post : posts) {
432→            ReaderPost existingPost = getBlogPost(post.blogId, post.postId, true);
433→            if (existingPost == null) {
434→                return ReaderActions.UpdateResult.HAS_NEW;
435→            } else if (!hasChanges && !post.isSamePost(existingPost)) {
436→                hasChanges = true;
437→            }
438→        }
439→
440→        return (hasChanges ? ReaderActions.UpdateResult.CHANGED : ReaderActions.UpdateResult.UNCHANGED);
441→    }
