896→                + "?48,?49,?50,?51,?52,?53)");
897→
898→        db.beginTransaction();
899→        try {
900→            String tagName = (tag != null ? tag.getTagSlug() : "");
901→            int tagType = (tag != null ? tag.tagType.toInt() : 0);
902→
903→            ReaderBlogIdPostId postWithGapMarker = getGapMarkerIdsForTag(tag);
904→
905→            for (ReaderPost post : posts) {
906→                // Skip blocked content
907→                if (BlockedAuthorTable.isBlockedAuthor(post)) continue;
908→                if (ReaderBlockedBlogTable.isBlockedBlog(post)) continue;
909→
910→                // keep the gapMarker flag
911→                boolean hasGapMarker = postWithGapMarker != null && postWithGapMarker.getPostId() == post.postId
912→                                       && postWithGapMarker.getBlogId() == post.blogId;
913→                stmtPosts.bindLong(1, post.postId);
914→                stmtPosts.bindLong(2, post.blogId);
915→                stmtPosts.bindLong(3, post.feedId);
916→                stmtPosts.bindLong(4, post.feedItemId);
