918→                stmtPosts.bindString(6, post.getAuthorName());
919→                stmtPosts.bindString(7, post.getAuthorFirstName());
920→                stmtPosts.bindLong(8, post.authorId);
921→                stmtPosts.bindString(9, post.getTitle());
922→                stmtPosts.bindString(10, maxText(post));
923→                stmtPosts.bindString(11, post.getExcerpt());
924→                stmtPosts.bindString(12, post.getFormat());
