935→                stmtPosts.bindString(23, post.getDateLiked());
936→                stmtPosts.bindString(24, post.getDateTagged());
937→                stmtPosts.bindLong(25, post.numReplies);
938→                stmtPosts.bindLong(26, post.numLikes);
939→                stmtPosts.bindLong(27, SqlUtils.boolToSql(post.isLikedByCurrentUser));
940→                stmtPosts.bindLong(28, SqlUtils.boolToSql(post.isFollowedByCurrentUser));
941→                stmtPosts.bindLong(29, SqlUtils.boolToSql(post.isCommentsOpen));
942→                stmtPosts.bindLong(30, SqlUtils.boolToSql(post.isExternal));
943→                stmtPosts.bindLong(31, SqlUtils.boolToSql(post.isPrivate));
944→                stmtPosts.bindLong(32, SqlUtils.boolToSql(post.isVideoPress));
945→                stmtPosts.bindLong(33, SqlUtils.boolToSql(post.isJetpack));
946→                stmtPosts.bindString(34, post.getPrimaryTag());
947→                stmtPosts.bindString(35, post.getSecondaryTag());
948→                stmtPosts.bindString(36, post.getAttachmentsJson());
949→                stmtPosts.bindString(37, post.getDiscoverJson());
950→                stmtPosts.bindLong(38, post.xpostPostId);
951→                stmtPosts.bindLong(39, post.xpostBlogId);
952→                stmtPosts.bindString(40, post.getRailcarJson());
953→                stmtPosts.bindString(41, tagName);
954→                stmtPosts.bindLong(42, tagType);
955→                stmtPosts.bindLong(43, SqlUtils.boolToSql(hasGapMarker));
956→                stmtPosts.bindString(44, ReaderCardType.toString(post.getCardType()));
957→                stmtPosts.bindLong(45, SqlUtils.boolToSql(post.useExcerpt));
