965→                stmtPosts.bindString(53, post.getAuthorBlogUrl());
966→                stmtPosts.execute();
967→            }
968→
969→            db.setTransactionSuccessful();
970→            EventBus.getDefault().post(ReaderPostTableActionEnded.INSTANCE);
971→        } finally {
