 90→    /*
 91→     * use this to request a reduced size image from not photon capable sites
 92→     * (i.e. a private post - images in private posts can't use photon
 93→     * but these are usually wp images so they support the h= and w= query params)
 94→     */
 95→    private static String getImageForDisplayWithoutPhoton(
 96→            final String imageUrl,
 97→            int width,
 98→            int height,
 99→            boolean forceHttps
100→    ) {
101→        if (TextUtils.isEmpty(imageUrl)) {
102→            return "";
103→        }
104→
105→        final String query;
106→        if (width > 0 && height > 0) {
107→            query = "?w=" + width + "&h=" + height;
108→        } else if (width > 0) {
109→            query = "?w=" + width;
110→        } else if (height > 0) {
111→            query = "?h=" + height;
112→        } else {
113→            query = "";
114→        }
115→
116→        if (forceHttps) {
117→            // remove the existing query string, add the new one, and make sure the url is https:
118→            return UrlUtils.removeQuery(UrlUtils.makeHttps(imageUrl)) + query;
119→        } else {
120→            // remove the existing query string, add the new one
121→            return UrlUtils.removeQuery(imageUrl) + query;
122→        }
123→    }
