386→    private static boolean putIfAbsentDone(Map<String, ReaderTag> defaultTags, String key, ReaderTag tag) {
387→        boolean insertionDone = false;
388→
389→        if (defaultTags.get(key) == null) {
390→            defaultTags.put(key, tag);
