 22→/**
 23→ * tbl_tags stores the list of tags the user subscribed to or has by default
 24→ */
 25→public class ReaderTagTable {
 26→    protected static void createTables(SQLiteDatabase db) {
 27→        db.execSQL("CREATE TABLE tbl_tags ("
 28→                   + " tag_slug TEXT COLLATE NOCASE,"
 29→                   + " tag_display_name TEXT COLLATE NOCASE,"
 30→                   + " tag_title TEXT COLLATE NOCASE,"
 31→                   + " tag_type INTEGER DEFAULT 0,"
 32→                   + " endpoint TEXT,"
 33→                   + " date_updated TEXT,"
 34→                   + " PRIMARY KEY (tag_slug, tag_type)"
 35→                   + ")");
 36→    }
 37→
 38→    protected static void dropTables(SQLiteDatabase db) {
 39→        db.execSQL("DROP TABLE IF EXISTS tbl_tags");
 40→    }
 41→
 42→    /*
 43→     * returns true if tbl_tags is empty
 44→     */
 45→    public static boolean isEmpty() {
 46→        return (SqlUtils.getRowCount(ReaderDatabase.getReadableDb(), "tbl_tags") == 0);
 47→    }
 48→
 49→    /*
 50→     * replaces all tags with the passed list
 51→     */
 52→    public static void replaceTags(ReaderTagList tags) {
 53→        if (tags == null || tags.size() == 0) {
 54→            return;
 55→        }
 56→
 57→        SQLiteDatabase db = ReaderDatabase.getWritableDb();
 58→        db.beginTransaction();
 59→        try {
 60→            try {
 61→                // first delete all existing tags, then insert the passed ones
 62→                db.execSQL("DELETE FROM tbl_tags");
 63→                addOrUpdateTags(tags);
 64→                db.setTransactionSuccessful();
 65→            } catch (SQLException e) {
 66→                AppLog.e(T.READER, e);
 67→            }
 68→        } finally {
 69→            db.endTransaction();
 70→        }
 71→    }
 72→
 73→    /*
 74→     * similar to the above but only replaces followed tags
 75→     */
 76→    public static void replaceFollowedTags(ReaderTagList tags) {
 77→        if (tags == null || tags.size() == 0) {
 78→            return;
 79→        }
 80→
 81→        SQLiteDatabase db = ReaderDatabase.getWritableDb();
 82→        db.beginTransaction();
 83→        try {
 84→            try {
 85→                // first delete all existing followed tags, then insert the passed ones
 86→                String[] args = {Integer.toString(ReaderTagType.FOLLOWED.toInt())};
 87→                db.execSQL("DELETE FROM tbl_tags WHERE tag_type=?", args);
 88→                addOrUpdateTags(tags);
 89→                db.setTransactionSuccessful();
 90→            } catch (SQLException e) {
 91→                AppLog.e(T.READER, e);
 92→            }
 93→        } finally {
 94→            db.endTransaction();
 95→        }
 96→    }
