 98→    public static void addOrUpdateTag(ReaderTag tag) {
 99→        if (tag == null) {
100→            return;
101→        }
102→        ReaderTagList tags = new ReaderTagList();
103→        tags.add(tag);
104→        addOrUpdateTags(tags);
105→    }
