107→    public static void addOrUpdateTags(ReaderTagList tagList) {
108→        if (tagList == null || tagList.size() == 0) {
109→            return;
110→        }
111→        SQLiteStatement stmt = null;
112→        try {
113→            stmt = ReaderDatabase.getWritableDb().compileStatement(
114→                    "INSERT OR REPLACE INTO tbl_tags (tag_slug, tag_display_name, tag_title, tag_type, endpoint) "
115→                    + "VALUES (?1,?2,?3,?4,?5)");
116→
117→            for (ReaderTag tag : tagList) {
118→                stmt.bindString(1, tag.getTagSlug());
119→                stmt.bindString(2, tag.getTagDisplayName());
120→                stmt.bindString(3, tag.getTagTitle());
121→                stmt.bindLong(4, tag.tagType.toInt());
122→                stmt.bindString(5, tag.getEndpoint());
123→                stmt.execute();
124→            }
125→        } finally {
126→            SqlUtils.closeStatement(stmt);
127→        }
128→    }
