304→        Iterator<String> it = jsonTags.keys();
305→        if (!it.hasNext()) {
306→            return;
307→        }
308→
309→        // most popular tag & second most popular tag, based on usage count on this blog
310→        String mostPopularTag = null;
311→        String nextMostPopularTag = null;
312→        int popularCount = 0;
