346→    private static String extractTitle(final String excerpt, int maxLen) {
347→        if (TextUtils.isEmpty(excerpt)) {
348→            return null;
349→        }
350→
351→        if (excerpt.length() < maxLen) {
352→            return excerpt.trim();
353→        }
354→
355→        StringBuilder result = new StringBuilder();
356→        BreakIterator wordIterator = BreakIterator.getWordInstance();
357→        wordIterator.setText(excerpt);
358→        int start = wordIterator.first();
359→        int end = wordIterator.next();
360→        int totalLen = 0;
361→        while (end != BreakIterator.DONE) {
362→            String word = excerpt.substring(start, end);
363→            result.append(word);
364→            totalLen += word.length();
365→            if (totalLen >= maxLen) {
366→                break;
367→            }
368→            start = end;
369→            end = wordIterator.next();
370→        }
371→
372→        if (totalLen == 0) {
373→            return null;
374→        }
375→        return result.toString().trim() + "...";
376→    }
