702→    /*
703→     * returns true if the passed post appears to be the same as this one - used when posts are
704→     * retrieved to determine which ones are new/changed/unchanged
705→     */
706→    public boolean isSamePost(ReaderPost post) {
707→        return post != null
708→               && post.blogId == this.blogId
709→               && post.postId == this.postId
710→               && post.feedId == this.feedId
711→               && post.feedItemId == this.feedItemId
712→               && post.numLikes == this.numLikes
713→               && post.numReplies == this.numReplies
714→               && post.isFollowedByCurrentUser == this.isFollowedByCurrentUser
715→               && post.isLikedByCurrentUser == this.isLikedByCurrentUser
716→               && post.isCommentsOpen == this.isCommentsOpen
717→               && post.useExcerpt == this.useExcerpt
718→               && post.getTitle().equals(this.getTitle())
719→               && post.getExcerpt().equals(this.getExcerpt())
720→               && post.getText().equals(this.getText());
721→    }
